{
  "schema_version": "0.2",
  "mode": "design",
  "workflow_kind": "dynamic",
  "dependencies": {
    "parallel_units": true,
    "edges": [
      {
        "from": "route_audit_batch",
        "to": "final_route_audit_report",
        "type": "data",
        "reason": "the final report consumes the immutable result from every route audit and therefore must wait for the batch to settle"
      }
    ],
    "capacity_constraints": []
  },
  "dynamic": {
    "batch": {
      "handle": "route_audit_batch",
      "item_identity_source": "route_launch_snapshot"
    },
    "await": {
      "join": "all",
      "k": null,
      "quorum_basis": null,
      "eligible_identity_source": "route_launch_snapshot",
      "eligible_statuses": ["succeeded", "failed", "cancelled", "timed_out"],
      "wake_event": "route_audit_batch_settled"
    },
    "accounting": {
      "expected_identity_source": "route_launch_snapshot",
      "terminal_statuses": ["succeeded", "failed", "cancelled", "timed_out"],
      "duplicate_policy": "open",
      "unknown_policy": "open",
      "failure_policy": "open",
      "partial_policy": "open",
      "complete_label_requires": [
        "expected_vs_represented",
        "no_duplicates",
        "no_unknown_identities",
        "terminal_status_accounted",
        "no_unresolved_identities"
      ]
    },
    "reductions": [
      {
        "name": "final_route_audit_report_layer",
        "expected_identity_source": "route_launch_snapshot",
        "observed_result_source": "received_route_audit_result_records",
        "represented_identity_source": "identities_extracted_from_received_route_audit_results",
        "represented_identity_derivation": "from_observed_results",
        "status_count_source": "statuses_from_received_route_audit_results",
        "unresolved_identity_source": "expected_minus_observed_route_identities",
        "output_summary_identity_source": "emitted_final_route_audit_report_manifest"
      }
    ],
    "final_reconciliation": {
      "expected_summary_identity_source": "emitted_final_route_audit_report_manifest",
      "observed_summary_source": "received_final_route_audit_report_records",
      "represented_identity_derivation": "from_observed_summaries",
      "checks": [
        "expected_vs_represented",
        "duplicate",
        "unknown",
        "terminal_status",
        "unresolved"
      ]
    }
  },
  "open_points": [
    {
      "key": "duplicate_policy",
      "question": "If multiple result records are received for the same route identity, should the control plane reject the batch or tolerate duplicates while marking the report incomplete?"
    },
    {
      "key": "unknown_policy",
      "question": "If a result record appears for a route identity not present in the launch snapshot, should the control plane reject synthesis or ignore the unknown identity?"
    },
    {
      "key": "failure_policy",
      "question": "Does any failed, cancelled, or timed out route audit block final report synthesis, or may the report be emitted with those terminal outcomes represented?"
    },
    {
      "key": "partial_policy",
      "question": "When one or more expected route identities remain unresolved at fan-in time, should the final report be refused or emitted as explicitly incomplete?"
    }
  ],
  "scenarios": [
    {
      "kind": "positive",
      "expected": "all 40 launched route identities are represented exactly once by terminal route audit results, the control plane wakes on route_audit_batch_settled, emits the final route audit report manifest, and final reconciliation can label the report complete"
    },
    {
      "kind": "missing",
      "expected": "one or more of the 40 expected route identities have no observed result record, so accounting shows unresolved identities and the complete label cannot be applied"
    },
    {
      "kind": "duplicate",
      "expected": "a route identity is represented by more than one observed result record, so accounting detects duplicates and downstream completeness depends on the unresolved duplicate policy"
    },
    {
      "kind": "failed",
      "expected": "one route audit reaches terminal status failed, which still counts for await eligibility, and whether final synthesis is blocked remains governed by the open failure policy"
    },
    {
      "kind": "timed_out",
      "expected": "one route audit reaches terminal status timed_out, which still counts for await eligibility, and whether final synthesis is blocked remains governed by the open failure policy"
    },
    {
      "kind": "unknown",
      "expected": "an observed result record names a route identity absent from route_launch_snapshot, so accounting flags an unknown identity and downstream handling remains governed by the open unknown policy"
    },
    {
      "kind": "partial_refused",
      "expected": "if partial_policy is later set to reject, any unresolved expected route identity prevents emission of a complete final report artifact"
    },
    {
      "kind": "partial_allowed",
      "expected": "if partial_policy is later set to allow_incomplete, the control plane may emit a final report artifact that explicitly records unresolved route identities as incomplete"
    }
  ],
  "boundary": {
    "control_plane": ["launch", "await", "accounting", "reconciliation", "control_plane_input_capacity"],
    "target_data_plane": ["workers", "scheduling", "persistence", "rate_limiting", "backpressure"]
  }
}

